    // Head & Face
    skinTone: '', skinColor: [], 
    hairStyle: '', hairColors: [],
    eyeFeature: '', eyeColors: [],
    denture: '', noseShape: '', faceMarkings: 'None',

    // Outfit
    headwear: '', upperBody: '', lowerBody: '', fullBody: '', footwear: '', 
    outfitColors: [],
    heldItem: '', classExtras: '',

    // Visuals & Tech
    style: '', setting: '', background: '', emotion: '', pose: '', action: '', 
