        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              label: { type: Type.STRING },
              prompt: { type: Type.STRING }
            },
            required: ["label", "prompt"]
          }
        },
      },
    });

    const jsonText = response.text;
    if (!jsonText) throw new Error("No response text");

    return JSON.parse(jsonText) as ExpressionEntry[];
  });
};

